SELECT DISTINCT ?movie ?movieLabel WHERE {
  wd:Q873 p:P166 ?awardStatement.
  ?awardStatement ps:P166 ?award.
  ?awardStatement pq:P1346 ?movie.
  ?award wdt:P585 ?awardDate.
  FILTER (YEAR(?awardDate) = 2012)
  OPTIONAL { ?movie rdfs:label ?movieLabel. FILTER (LANG(?movieLabel) = "en") }
}

